  "application-properties": "#\n# Copyright (c) 2023-2025 Mariano Barcia\n#\n# Licensed under the Apache License, Version 2.0 (the \"License\");\n# you may not use this file except in compliance with the License.\n# You may obtain a copy of the License at\n#\n#     http://www.apache.org/licenses/LICENSE-2.0\n#\n# Unless required by applicable law or agreed to in writing, software\n# distributed under the License is distributed on an \"AS IS\" BASIS,\n# WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n# See the License for the specific language governing permissions and\n# limitations under the License.\n#\n\n# Vert.x configuration\nquarkus.http.ssl-port={{add 8443 portOffset}}\n# REST alternative:\n# quarkus.http.port={{add 8443 portOffset}}\n# quarkus.http.enable-compression=true\n\n# HTTP/2 REST and gRPC endpoint using SSL with a self-signed cert\nquarkus.grpc.server.use-separate-server=false\nquarkus.grpc.server.plain-text=false\nquarkus.http.ssl.certificate.key-store-file=${SERVER_KEYSTORE_PATH:../target/dev-certs/{{serviceName}}/server-keystore.jks}\nquarkus.http.ssl.certificate.key-store-password=secret\nquarkus.http.insecure-requests=disabled\n{{#if hasQueueAsyncRuntime}}\n\n# Await steps and checkpoint hand-offs require queue-async orchestration so executions can park, resume, or publish boundaries.\npipeline.orchestrator.mode=QUEUE_ASYNC\npipeline.orchestrator.resume-token-secret=${TPF_RESUME_TOKEN_SECRET}\n{{#if hasCheckpointBoundaries}}\n# Keep checkpoint publishers/subscribers idempotent over the configured boundary key fields.\n{{/if}}\n{{/if}}\n{{#if kafkaAwait}}\n\n# Kafka await transport starter settings.\ntpf.await.kafka.reactive-messaging.enabled=true\nkafka.bootstrap.servers=${KAFKA_BOOTSTRAP_SERVERS:localhost:9092}\nmp.messaging.outgoing.tpf-await-kafka-requests.connector=smallrye-kafka\nmp.messaging.outgoing.tpf-await-kafka-requests.topic={{kafkaAwait.requestTopic}}\nmp.messaging.outgoing.tpf-await-kafka-requests.value.serializer=org.apache.kafka.common.serialization.StringSerializer\nmp.messaging.incoming.tpf-await-kafka-responses.connector=smallrye-kafka\nmp.messaging.incoming.tpf-await-kafka-responses.topic={{kafkaAwait.responseTopic}}\nmp.messaging.incoming.tpf-await-kafka-responses.group.id={{kafkaAwait.consumerGroupProperty}}\nmp.messaging.incoming.tpf-await-kafka-responses.auto.offset.reset=${TPF_AWAIT_KAFKA_RESPONSES_OFFSET_RESET:earliest}\nmp.messaging.incoming.tpf-await-kafka-responses.value.deserializer=org.apache.kafka.common.serialization.StringDeserializer\n{{/if}}\n\n# Micrometer configuration\nquarkus.micrometer.export.prometheus.enabled=${QUARKUS_MICROMETER_EXPORT_PROMETHEUS_ENABLED:false}\nquarkus.micrometer.export.prometheus.path=/q/metrics\nquarkus.micrometer.binder.http-server.enabled=${QUARKUS_OTEL_METRICS_ENABLED:${QUARKUS_MICROMETER_EXPORT_PROMETHEUS_ENABLED:true}}\nquarkus.micrometer.binder.http-client.enabled=${QUARKUS_OTEL_METRICS_ENABLED:${QUARKUS_MICROMETER_EXPORT_PROMETHEUS_ENABLED:true}}\nquarkus.micrometer.binder.jvm=true\n\n# OpenTelemetry defaults\nquarkus.otel.exporter.otlp.protocol=http/protobuf\nquarkus.otel.exporter.otlp.compression=gzip\nquarkus.otel.exporter.otlp.metrics.temporality.preference=delta\n# For non-local deployments, set OTEL_EXPORTER_OTLP_ENDPOINT or quarkus.otel.exporter.otlp.endpoint.\n# quarkus.otel.exporter.otlp.endpoint=${OTEL_EXPORTER_OTLP_ENDPOINT}\n# Prometheus export is opt-in to avoid running LGTM/Prometheus by default in dev.\n# The following defaults only apply when OpenTelemetry is enabled (for example via NEW_RELIC_LICENSE_KEY).\nquarkus.otel.traces.enabled=true\nquarkus.otel.metrics.enabled=true\nquarkus.otel.metric.export.interval=${QUARKUS_OTEL_METRIC_EXPORT_INTERVAL:10s}\nquarkus.otel.traces.sampler=parentbased_traceidratio\nquarkus.otel.traces.sampler.arg=0.001\nquarkus.otel.resource.attributes=service.instance.id=${HOSTNAME:unknown}\n\n# Docker image\nquarkus.container-image.builder=jib\nquarkus.container-image.registry=localhost\nquarkus.container-image.group={{rootProjectName}}\nquarkus.container-image.name={{serviceName}}\nquarkus.container-image.tag=latest\n",
  "application-test-properties": "#\n# Copyright (c) 2023-2025 Mariano Barcia\n#\n# Licensed under the Apache License, Version 2.0 (the \"License\");\n# you may not use this file except in compliance with the License.\n# You may obtain a copy of the License at\n#\n#     http://www.apache.org/licenses/LICENSE-2.0\n#\n# Unless required by applicable law or agreed to in writing, software\n# distributed under the License is distributed on an \"AS IS\" BASIS,\n# WITHOUT WARRANTIES OR CONDITIONS OF ANY KIND, either express or implied.\n# See the License for the specific language governing permissions and\n# limitations under the License.\n#\n\nquarkus.http.test-port=0\n\n# Disable OTEL during tests\nquarkus.otel.enabled=false\nquarkus.otel.traces.enabled=false\nquarkus.otel.metrics.enabled=false\nquarkus.otel.logs.enabled=false\nquarkus.otel.sdk.disabled=true\nquarkus.observability.lgtm.enabled=false\n\n# Micrometer configuration\nquarkus.micrometer.export.prometheus.enabled=false\n",
  "base-entity": "package {{basePackage}}.common.domain;\n\nimport jakarta.persistence.Column;\nimport jakarta.persistence.Id;\nimport jakarta.persistence.MappedSuperclass;\nimport jakarta.persistence.PrePersist;\nimport java.util.UUID;\nimport lombok.Getter;\nimport lombok.Setter;\n\n@Setter\n@Getter\n@MappedSuperclass\npublic abstract class BaseEntity {\n\n  @Id\n  @Column(name = \"id\", updatable = false, nullable = false)\n  public UUID id;\n\n  public BaseEntity() {\n    id = UUID.randomUUID();\n  }\n\n  @PrePersist\n  protected void ensureId() {\n    if (id == null) {\n      id = UUID.randomUUID();\n    }\n  }\n}\n",
