  "union-dto-json-serializer": "package {{basePackage}}.common.dto;\n\nimport com.fasterxml.jackson.core.JsonGenerator;\nimport com.fasterxml.jackson.databind.JsonSerializer;\nimport com.fasterxml.jackson.databind.SerializerProvider;\nimport java.io.IOException;\n\npublic final class {{dtoName}}JsonSerializer extends JsonSerializer<{{dtoName}}> {\n\n  @Override\n  public void serialize({{dtoName}} value, JsonGenerator gen, SerializerProvider serializers)\n      throws IOException {\n    gen.writeStartObject();\n{{#each variants}}\n    {{#if @first}}if{{else}}else if{{/if}} (value instanceof {{dtoTypeName}} variant) {\n      gen.writeStringField(\"type\", \"{{name}}\");\n      gen.writeObjectField(\"{{name}}\", variant);\n    }\n{{/each}}\n    else {\n      throw new IOException(\"Unsupported {{dtoName}} type: \" + value.getClass().getName());\n    }\n    gen.writeEndObject();\n  }\n}\n",
  "union-dto-variant": "package {{basePackage}}.common.dto;\n\nimport com.fasterxml.jackson.annotation.JsonIgnoreProperties;\nimport com.fasterxml.jackson.annotation.JsonTypeName;\nimport java.io.Serializable;\nimport java.util.UUID;\n\n{{#if hasDateFields}}\nimport java.time.LocalDate;\nimport java.time.LocalDateTime;\nimport java.time.OffsetDateTime;\nimport java.time.ZonedDateTime;\nimport java.time.Instant;\nimport java.time.Duration;\nimport java.time.Period;\n{{/if}}\n{{#if hasBigIntegerFields}}\nimport java.math.BigInteger;\n{{/if}}\n{{#if hasBigDecimalFields}}\nimport java.math.BigDecimal;\n{{/if}}\n{{#if hasCurrencyFields}}\nimport java.util.Currency;\n{{/if}}\n{{#if hasPathFields}}\nimport java.nio.file.Path;\n{{/if}}\n{{#if hasNetFields}}\nimport java.net.URI;\nimport java.net.URL;\n{{/if}}\n{{#if hasIoFields}}\nimport java.io.File;\n{{/if}}\n{{#if hasAtomicFields}}\nimport java.util.concurrent.atomic.AtomicInteger;\nimport java.util.concurrent.atomic.AtomicLong;\n{{/if}}\n{{#if hasUtilFields}}\nimport java.util.List;\n{{/if}}\n{{#if hasMapFields}}\nimport java.util.Map;\n{{/if}}\n\n@JsonTypeName(\"{{name}}\")\n@JsonIgnoreProperties(ignoreUnknown = true)\npublic final class {{dtoTypeName}} implements {{unionDtoName}}, Serializable {\n{{#each fields}}\n  public {{{this.type}}} {{this.javaName}};\n{{/each}}\n}\n",
  "union-mapper": "package {{basePackage}}.common.mapper;\n\nimport jakarta.enterprise.context.ApplicationScoped;\nimport org.pipelineframework.mapper.Mapper;\n{{#each variants}}\nimport {{../basePackage}}.common.domain.{{typeName}};\nimport {{../basePackage}}.common.dto.{{dtoTypeName}};\n{{/each}}\nimport {{basePackage}}.common.domain.{{name}};\nimport {{basePackage}}.common.dto.{{dtoName}};\n\n@ApplicationScoped\npublic class {{name}}Mapper implements Mapper<{{name}}, {{dtoName}}> {\n\n  @Override\n  public {{name}} fromExternal({{dtoName}} external) {\n    if (external == null) {\n      return null;\n    }\n{{#each variants}}\n    {{#if @first}}if{{else}}else if{{/if}} (external instanceof {{dtoTypeName}} source) {\n      {{typeName}} target = new {{typeName}}();\n{{#each fields}}\n{{#unless (isIdField this.name)}}\n      target.{{javaName}} = source.{{javaName}};\n{{/unless}}\n{{/each}}\n      return target;\n    }\n{{/each}}\n    throw new IllegalArgumentException(\"Unsupported {{dtoName}} variant: \" + external);\n  }\n\n  @Override\n  public {{dtoName}} toExternal({{name}} domain) {\n    if (domain == null) {\n      return null;\n    }\n{{#each variants}}\n    {{#if @first}}if{{else}}else if{{/if}} (domain instanceof {{typeName}} source) {\n      {{dtoTypeName}} target = new {{dtoTypeName}}();\n{{#each fields}}\n{{#unless (isIdField this.name)}}\n      target.{{javaName}} = source.{{javaName}};\n{{/unless}}\n{{/each}}\n      return target;\n    }\n{{/each}}\n    throw new IllegalArgumentException(\"Unsupported {{name}} variant: \" + domain);\n  }\n}\n"
